#[derive(Args)]
pub struct PwCmd {
    /// 指定密码长度，默认为16位
    #[arg(short = 'l', long, help = "密码长度", default_value = "16")]
    pub length: usize,

    /// 是否包含特殊字符
    #[arg(short = 's', long, help = "包含特殊字符", default_value = "false")]
    pub special: bool,
}

impl PwCmd {
    /// 执行密码生成命令
    pub fn execute(&self) {
        println!("{}", self.generate());
    }

    /// 生成指定长度的随机密码
    /// 包含大小写字母、数字
    pub fn generate(&self) -> String {
        const CHARSET: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZ\
                                abcdefghijklmnopqrstuvwxyz\
                                0123456789";
        const SPECIAL_CHARSET: &[u8] = b"!@#$%^&*()-_=+[]{}|;:',.<>?/`~";
        let mut rng = thread_rng();
        let charset = if self.special {
            [CHARSET, SPECIAL_CHARSET].concat()
        } else {
            CHARSET.to_vec()
        };
        let password: String = (0..self.length)
            .map(|_| {
                let idx = rng.gen_range(0..charset.len());
                charset[idx] as char
            })
            .collect();
        password
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_generate_default_length() {
        let cmd = PwCmd {
            length: 16,
            special: false,
        };
        let pw = cmd.generate();
        assert_eq!(pw.len(), 16);
        assert!(pw.chars().all(|c| c.is_ascii_alphanumeric()));
    }

    #[test]
    fn test_generate_custom_length() {
        let cmd = PwCmd {
            length: 32,
            special: false,
        };
        let pw = cmd.generate();
        assert_eq!(pw.len(), 32);
    }

    #[test]
    fn test_generate_length_1() {
        let cmd = PwCmd {
            length: 1,
            special: false,
        };
        let pw = cmd.generate();
        assert_eq!(pw.len(), 1);
    }

    #[test]
    fn test_generate_length_0() {
        let cmd = PwCmd {
            length: 0,
            special: false,
        };
        let pw = cmd.generate();
        assert_eq!(pw.len(), 0);
        assert!(pw.is_empty());
    }

    #[test]
    fn test_generate_with_special_chars() {
        let cmd = PwCmd {
            length: 100,
            special: true,
        };
        let pw = cmd.generate();
        assert_eq!(pw.len(), 100);
        // 大样本下应包含特殊字符
        let has_special = pw.chars().any(|c| !c.is_ascii_alphanumeric());
        assert!(has_special, "密码应包含特殊字符");
    }

    #[test]
    fn test_generate_without_special_chars() {
        let cmd = PwCmd {
            length: 100,
            special: false,
        };
        let pw = cmd.generate();
        assert_eq!(pw.len(), 100);
        assert!(pw.chars().all(|c| c.is_ascii_alphanumeric()));
    }

    #[test]
    fn test_generate_uniqueness() {
        let cmd = PwCmd {
            length: 32,
            special: false,
        };
        let pw1 = cmd.generate();
        let pw2 = cmd.generate();
        assert_ne!(pw1, pw2);
    }

    #[test]
    fn test_execute_default() {
        let cmd = PwCmd {
            length: 16,
            special: false,
        };
        cmd.execute();
    }

    #[test]
    fn test_execute_with_special() {
        let cmd = PwCmd {
            length: 20,
            special: true,
        };
        cmd.execute();
    }
}

use clap::Args;
use sysinfo::System;

/// 系统工具
#[derive(Args)]
pub struct SysCmd {}

impl SysCmd {
    pub fn execute(&self) {
        let sys = System::new_all();
        let (used, total) = (
            sys.used_memory() as f64 / 1024f64.powi(3),
            sys.total_memory() as f64 / 1024f64.powi(3),
        );

        let cpu_count = sys.cpus().len();
        let cpu_name = sys.cpus().first().map(|c| c.brand()).unwrap_or("未知");

        let name = System::name().unwrap_or_else(|| "未知".to_string());
        let os_version = System::os_version().unwrap_or_else(|| "未知".to_string());
        let kernel = System::kernel_version().unwrap_or_else(|| "未知".to_string());

        let usage = if total > 0.0 { used / total * 100.0 } else { 0.0 };

        println!("操作系统: {}", name);
        println!("系统版本: {}", os_version);
        println!("内核版本: {}", kernel);
        println!("内存: {:.2}/{:.2} GB  使用率: {:.2}%", used, total, usage);
        println!("CPU: {}c ({})", cpu_count, cpu_name);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_execute_basic() {
        let cmd = SysCmd {};
        cmd.execute();
    }

    #[test]
    fn test_system_info_not_empty() {
        let sys = System::new_all();
        let name = System::name().unwrap_or_else(|| "未知".to_string());
        let os_version = System::os_version().unwrap_or_else(|| "未知".to_string());
        let kernel = System::kernel_version().unwrap_or_else(|| "未知".to_string());
        let cpu_count = sys.cpus().len();

        assert!(!name.is_empty());
        assert!(!os_version.is_empty());
        assert!(!kernel.is_empty());
        assert!(cpu_count > 0);
    }

    #[test]
    fn test_memory_usage_calculation() {
        let sys = System::new_all();
        let used = sys.used_memory() as f64 / 1024f64.powi(3);
        let total = sys.total_memory() as f64 / 1024f64.powi(3);

        if total > 0.0 {
            let usage = used / total * 100.0;
            assert!(usage >= 0.0 && usage <= 100.0);
        } else {
            // total == 0.0 的情况（理论上在真实系统上不会发生）
            assert_eq!(total, 0.0);
        }
    }

    #[test]
    fn test_cpu_name_not_empty() {
        let sys = System::new_all();
        let cpu_name = sys.cpus().first().map(|c| c.brand()).unwrap_or("未知");
        assert!(!cpu_name.is_empty());
    }
}

use chrono::{DateTime, Duration, Local, Utc};
use chrono_tz::Tz;
use clap::Args;
use std::str::FromStr;

/// 时间工具
#[derive(Args)]
pub struct TimeCmd {
    /// 显示指定时区的时间，例如: Asia/Shanghai, America/New_York
    #[arg(short, long)]
    pub timezone: Option<String>,

    /// 显示Unix时间戳
    #[arg(short, long)]
    pub unix: bool,

    /// 格式化时间，例如: %Y-%m-%d %H:%M:%S
    #[arg(short, long, default_value = "%Y-%m-%d %H:%M:%S")]
    pub format: String,

    /// 倒计时秒数
    #[arg(short, long)]
    pub countdown: Option<u64>,
}

impl TimeCmd {
    pub fn execute(&self) {
        if let Some(seconds) = self.countdown {
            self.run_countdown(seconds);
            return;
        }

        self.print_current_time();
    }

    fn print_current_time(&self) {
        let now_local: DateTime<Local> = Local::now();
        let now_utc: DateTime<Utc> = Utc::now();

        println!("当前本地时间: {}", now_local.format(&self.format));
        println!("当前UTC时间: {}", now_utc.format(&self.format));

        if self.unix {
            println!("Unix时间戳: {}", now_utc.timestamp());
        }

        if let Some(tz_str) = &self.timezone {
            match Tz::from_str(tz_str) {
                Ok(tz) => {
                    let time_in_tz = now_utc.with_timezone(&tz);
                    println!("{}时间: {}", tz_str, time_in_tz.format(&self.format));
                }
                Err(_) => {
                    println!("错误: 无效的时区 '{}'", tz_str);
                    println!("提示: 时区格式应为 'Region/City'，例如 'Asia/Shanghai'");
                }
            }
        }
    }

    fn run_countdown(&self, seconds: u64) {
        println!("开始倒计时 {} 秒", seconds);

        let start_time = Local::now();
        let end_time = start_time + Duration::seconds(seconds as i64);

        while Local::now() < end_time {
            let remaining = end_time - Local::now();
            let remaining_secs = remaining.num_seconds();

            print!(
                "\r剩余时间: {:02}:{:02}",
                remaining_secs / 60,
                remaining_secs % 60
            );

            let _ = std::io::Write::flush(&mut std::io::stdout());
            std::thread::sleep(std::time::Duration::from_millis(100));
        }

        println!("\n倒计时结束!");
    }
}

